module RefModule(
        input   wire [31:0]   op1,
        input   wire [4:0]    shamt,
        input   wire [1:0]    operation,
        output  wire [31:0]   res
    );reg [31:0] obf_shift_res;
    reg [31:0] sign_bits;

    assign res = obf_shift_res;

    always @ *
    case (operation)
        2'b01: obf_shift_res = (op1 <<  shamt); 
        2'b10: obf_shift_res = (op1 >>  shamt); 
        2'b11: begin


          sign_bits = 32'hFFFFFFFF << (5'h1F - shamt);
          obf_shift_res = (op1 >> shamt);
          obf_shift_res = op1[31] ? sign_bits | obf_shift_res : obf_shift_res;
        end
        default: obf_shift_res = 32'bx;
    endcase

endmodule
